class Solution {
public:
    bool find132pattern(vector<int>& nums) {
        stack<int> st; int third=INT_MIN;
        for(int i=nums.size()-1;i>=0;i--){
            if(nums[i]<third) return true;
            while(!st.empty()&&nums[i]>st.top()){ third=st.top(); st.pop(); }
            st.push(nums[i]);
        }
        return false;
    }
};

