bool find132pattern(int* nums, int n) {
    int* st=malloc(n*sizeof(int)); int top=0, third=INT_MIN;
    for(int i=n-1;i>=0;i--){
        if(nums[i]<third){ free(st); return true; }
        while(top&&nums[i]>st[top-1]) third=st[--top];
        st[top++]=nums[i];
    }
    free(st); return false;
}
